	{
		c[i]=c[i-1]*i%MOD;
	}
    cout<<c[n]*Quick_Pow(c[n-m],MOD-2,MOD)%MOD*Quick_Pow(c[m],MOD-2,MOD)%MOD;
    return false;
}
